#include <stdio.h>
#include <string.h>

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        char s[100001];
        scanf("%s", s);
        int c = 0, h = 0, e = 0, f = 0;
        int res = 0;
        for (int i = 0; i < strlen(s); i++) {
            if (s[i] == 'C') c++;
            else if (s[i] == 'H') h++;
            else if (s[i] == 'E') e++;
            else if (s[i] == 'F') f++;
            if (c > 0 && h > 0 && e > 0 && f > 0) {
                res++;
                c--;
                h--;
                e--;
                f--;
            }
        }
        printf("%d\n", res);
    }
    return 0;
}

