import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int t = sc.nextInt();
        while (t-- > 0) {
            String s = sc.next();
            int c = 0, h = 0, e = 0, f = 0;
            int res = 0;
            for (int i = 0; i < s.length(); i++) {
                if (s.charAt(i) == 'C') c++;
                else if (s.charAt(i) == 'H') h++;
                else if (s.charAt(i) == 'E') e++;
                else if (s.charAt(i) == 'F') f++;
                if (c > 0 && h > 0 && e > 0 && f > 0) {
                    res++;
                    c--;
                    h--;
                    e--;
                    f--;
                }
            }
            System.out.println(res);
        }
    }
}

